sql:
SELECT alternative_name
  FROM alternative_names
  WHERE stadium_id = 0;

SELECT MAX(upload_date) AS latest_upload_date
FROM stadium_images
WHERE stadium_id = 1;

SELECT name AS stadium_name
FROM stadiums
ORDER BY start_date ASC;

SELECT name 
FROM stadiums 
ORDER BY name;

SELECT name
FROM stadiums
WHERE stadium_id = 0;

SELECT COUNT(image_id) AS total_images
FROM stadium_images
WHERE stadium_id = 0;

SELECT COUNT(*) AS active_stadiums
FROM stadiums
WHERE end_date IS NULL;

SELECT name AS stadium_name
FROM stadiums
ORDER BY start_date ASC, name ASC;

SELECT name 
FROM stadiums 
ORDER BY start_date, name;
